/**
 * Reign of Brabant -- Unit Voice Lines
 *
 * Plays faction-specific voice responses when units are selected, moved,
 * ordered to attack, or sent to gather resources. Each action has multiple
 * voice variants that are picked at random.
 *
 * Voice files are generated by scripts/generate_unit_voices.sh via the
 * ElevenLabs TTS API.
 *
 * Integration: call playUnitVoice(factionId, action) from Game.ts when
 * the player interacts with a unit.
 */

import { Howl } from 'howler';
import { audioManager } from './AudioManager';

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export type VoiceAction = 'select' | 'move' | 'attack' | 'gather';

// ---------------------------------------------------------------------------
// Voice line definitions per faction
// ---------------------------------------------------------------------------

const VOICE_BASE = 'assets/audio/voices/';

const VOICE_LINES: Record<number, Record<VoiceAction, string[]>> = {
  // Faction 0 — Brabanders (warm, Brabants dialect)
  0: {
    select: [
      `${VOICE_BASE}brabanders/select_1.mp3`,
      `${VOICE_BASE}brabanders/select_2.mp3`,
      `${VOICE_BASE}brabanders/select_3.mp3`,
    ],
    move: [
      `${VOICE_BASE}brabanders/move_1.mp3`,
      `${VOICE_BASE}brabanders/move_2.mp3`,
      `${VOICE_BASE}brabanders/move_3.mp3`,
    ],
    attack: [
      `${VOICE_BASE}brabanders/attack_1.mp3`,
      `${VOICE_BASE}brabanders/attack_2.mp3`,
      `${VOICE_BASE}brabanders/attack_3.mp3`,
    ],
    gather: [
      `${VOICE_BASE}brabanders/gather_1.mp3`,
      `${VOICE_BASE}brabanders/gather_2.mp3`,
      `${VOICE_BASE}brabanders/gather_3.mp3`,
    ],
  },

  // Faction 1 — Randstad (corporate, stiff/formal)
  1: {
    select: [
      `${VOICE_BASE}randstad/select_1.mp3`,
      `${VOICE_BASE}randstad/select_2.mp3`,
      `${VOICE_BASE}randstad/select_3.mp3`,
    ],
    move: [
      `${VOICE_BASE}randstad/move_1.mp3`,
      `${VOICE_BASE}randstad/move_2.mp3`,
      `${VOICE_BASE}randstad/move_3.mp3`,
    ],
    attack: [
      `${VOICE_BASE}randstad/attack_1.mp3`,
      `${VOICE_BASE}randstad/attack_2.mp3`,
      `${VOICE_BASE}randstad/attack_3.mp3`,
    ],
    gather: [
      `${VOICE_BASE}randstad/gather_1.mp3`,
      `${VOICE_BASE}randstad/gather_2.mp3`,
      `${VOICE_BASE}randstad/gather_3.mp3`,
    ],
  },
};

// ---------------------------------------------------------------------------
// Cooldown — prevent overlapping voice lines
// ---------------------------------------------------------------------------

let lastVoiceTime = 0;
const VOICE_COOLDOWN = 800; // ms between voice lines

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

/**
 * Play a random voice line for the given faction and action.
 *
 * Respects a global cooldown so rapid clicks don't stack voice clips.
 * Ducks the music track while the voice plays for clarity.
 *
 * @param factionId - 0 = Brabanders, 1 = Randstad
 * @param action    - 'select' | 'move' | 'attack' | 'gather'
 */
export function playUnitVoice(factionId: number, action: VoiceAction): void {
  const now = Date.now();
  if (now - lastVoiceTime < VOICE_COOLDOWN) return;

  const factionLines = VOICE_LINES[factionId];
  if (!factionLines) return;

  const lines = factionLines[action];
  if (!lines || lines.length === 0) return;

  // Pick a random variant
  const src = lines[Math.floor(Math.random() * lines.length)];

  const sound = new Howl({
    src: [src],
    volume: 0.6,
    onplay: () => {
      // Duck music while voice plays so the line is audible
      audioManager.duckMusic(1500);
    },
  });

  sound.play();
  lastVoiceTime = now;
}
